python3 -c "
import json
import re

# Read files
with open('manifest.json', 'r') as f:
    manifest = json.load(f)

with open('schema.json', 'r') as f:
    schema = json.load(f)

# Manual validation
errors = []

# Check release
if 'release' not in manifest:
    errors.append('Missing required field: release')
elif not re.match(schema['properties']['release']['pattern'], manifest['release']):
    errors.append(f'Invalid release format: {manifest[\"release\"]}')

# Check components
if 'components' not in manifest:
    errors.append('Missing required field: components')
elif not isinstance(manifest['components'], list):
    errors.append('components must be an array')
elif len(manifest['components']) != 3:
    errors.append(f'components must have exactly 3 items, got {len(manifest[\"components\"])}')
else:
    names = set()
    for i, comp in enumerate(manifest['components']):
        # Check required fields
        if 'name' not in comp or 'version' not in comp:
            errors.append(f'Component {i} missing required fields')

        # Check for extra properties
        valid_props = {'name', 'version'}
        extra_props = set(comp.keys()) - valid_props
        if extra_props:
            errors.append(f'Component {i} has extra properties: {extra_props}')

        # Validate name
        if 'name' in comp and not isinstance(comp['name'], str) or len(comp['name']) == 0:
            errors.append(f'Component {i} name is invalid')

        # Check name uniqueness
        if 'name' in comp:
            if comp['name'] in names:
                errors.append(f'Duplicate component name: {comp[\"name\"]}')
            names.add(comp['name'])

        # Validate version
        if 'version' in comp:
            if not re.match(r'^[0-9]+\.[0-9]+\.[0-9]+$', comp['version']):
                errors.append(f'Component {i} version invalid: {comp[\"version\"]}')

# Check for extra properties at root
valid_props = {'release', 'components'}
extra_props = set(manifest.keys()) - valid_props
if extra_props:
    errors.append(f'Root object has extra properties: {extra_props}')

if errors:
    print('✗ Validation FAILED:')
    for error in errors:
        print(f'  - {error}')
    exit(1)
else:
    print('✓ manifest.json validates against schema.json')
    print('Manifest:')
    print(json.dumps(manifest, indent=2))
"
